import { Accordion as AccordionPrimitive } from "@base-ui/react/accordion";
import { createStyleContext } from "@/registry/bare/lib/create-style-context";
import { createPropSplitter } from "@/registry/bare/lib/split-variant-props";
import { accordionStyles } from "./styles";
import type { VariantProps } from "@/registry/bare/lib/tv.config";

type AccordionStyles = ReturnType<typeof accordionStyles>;
type AccordionVariantProps = VariantProps<typeof accordionStyles>;

const { StyleContext, useStyles } =
  createStyleContext<AccordionStyles>("Accordion");
const splitProps = createPropSplitter(accordionStyles);

export { useStyles as useAccordionStyles };

interface AccordionRootProps
  extends AccordionPrimitive.Root.Props,
    AccordionVariantProps {
  className?: string;
  styles?: AccordionStyles;
}

export function AccordionRoot(props: AccordionRootProps) {
  const [variantProps, { className, styles, ...htmlProps }] = splitProps(
    props as Record<string, any>,
  );
  const s = styles ?? accordionStyles(variantProps);
  return (
    <StyleContext value={s}>
      <AccordionPrimitive.Root
        {...htmlProps}
        className={s.root({ class: className })}
        data-slot="accordion"
      />
    </StyleContext>
  );
}

import { Accordion as AccordionPrimitive } from "@base-ui/react/accordion";
import { useAccordionStyles } from "./accordion-root";

interface AccordionItemProps extends AccordionPrimitive.Item.Props {
  className?: string;
}

export function AccordionItem({ className, ...props }: AccordionItemProps) {
  const styles = useAccordionStyles();
  return (
    <AccordionPrimitive.Item
      {...props}
      className={styles.item({ class: className })}
      data-slot="accordion-item"
    />
  );
}

interface AccordionHeaderProps extends AccordionPrimitive.Header.Props {
  className?: string;
}

export function AccordionHeader({
  className,
  ...props
}: AccordionHeaderProps) {
  const styles = useAccordionStyles();
  return (
    <AccordionPrimitive.Header
      {...props}
      className={styles.header({ class: className })}
      data-slot="accordion-header"
    />
  );
}

interface AccordionTriggerProps extends AccordionPrimitive.Trigger.Props {
  className?: string;
}

export function AccordionTrigger({
  className,
  ...props
}: AccordionTriggerProps) {
  const styles = useAccordionStyles();
  return (
    <AccordionPrimitive.Trigger
      {...props}
      className={styles.trigger({ class: className })}
      data-slot="accordion-trigger"
    />
  );
}

interface AccordionPanelProps extends AccordionPrimitive.Panel.Props {
  className?: string;
}

export function AccordionPanel({
  className,
  ...props
}: AccordionPanelProps) {
  const styles = useAccordionStyles();
  return (
    <AccordionPrimitive.Panel
      {...props}
      className={styles.panel({ class: className })}
      data-slot="accordion-panel"
    />
  );
}

import { tv } from "@/registry/bare/lib/tv.config";

export const accordionStyles = tv({
  slots: {
    root: [""],
    item: [""],
    header: [""],
    trigger: [""],
    panel: [""],
  },
});

export { AccordionRoot } from "./accordion-root";
export {
  AccordionItem,
  AccordionHeader,
  AccordionTrigger,
  AccordionPanel,
} from "./accordion-parts";

export { AccordionRoot as Accordion } from "./accordion-root";
export {
  AccordionItem,
  AccordionHeader,
  AccordionTrigger,
  AccordionPanel,
} from "./accordion-parts";
export { accordionStyles } from "./styles";
